// Worked focus: httpsts-host-port-allowlist — Validate canonical host and port against configured authority before routing, link generation, cache keys, redirects, or tenant selection.
// Evidence: httpsts-worked-http-server-ts-request-authority-proxy-3
// Competency: httpsts-worked-http-server-ts-request-authority-proxy-3.
// Case 5798: privacy-sensitive records API using conditional requests.
// Operating constraint: retain a screen-reader-readable decision trace.
// Changed case: change the tenant and prove denial before repository access.
function worked_http_server_ts_request_authority_proxy_3(host: string, forwardedHost: string, trustedProxy: boolean): { authority: string; allowed: boolean } {
  const authority = trustedProxy && forwardedHost.length > 0 ? forwardedHost : host;
  const normalized = authority.toLowerCase();
  const allowed = normalized === "api.example.test" || normalized === "api.example.test:443";
  return { authority: normalized, allowed };
}

